using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

/// <summary>
/// Shared helpers for creating in-memory SchoolContext instances and seed data.
/// </summary>
public static class TestHelpers
{
    public static SchoolContext CreateContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static SchoolContext CreateSeededContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var context = CreateContext(dbName);
        SeedData(context);
        return context;
    }

    public static void SeedData(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11")
        };
        var instructor2 = new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06")
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor1.ID
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course1 = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        var course2 = new Course
        {
            CourseID = 4022,
            Title = "Microeconomics",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        var student1 = new Student
        {
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2010-09-01")
        };
        var student2 = new Student
        {
            FirstMidName = "Meredith",
            LastName = "Alonso",
            EnrollmentDate = DateTime.Parse("2012-09-01")
        };
        var student3 = new Student
        {
            FirstMidName = "Arturo",
            LastName = "Anand",
            EnrollmentDate = DateTime.Parse("2013-09-01")
        };
        context.Students.AddRange(student1, student2, student3);
        context.SaveChanges();

        context.Enrollments.Add(new Enrollment
        {
            StudentID = student1.ID,
            CourseID = course1.CourseID,
            Grade = Grade.A
        });
        context.SaveChanges();

        context.CourseAssignments.Add(new CourseAssignment
        {
            CourseID = course1.CourseID,
            InstructorID = instructor1.ID
        });
        context.SaveChanges();

        context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor2.ID,
            Location = "Smith 17"
        });
        context.SaveChanges();
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut = new();

    public void Dispose() => _sut.Dispose();

    // Drain any leftover notifications from the static queue so tests don't interfere
    private void DrainQueue()
    {
        while (_sut.ReceiveNotification() != null) { }
    }

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        DrainQueue();
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityId()
    {
        DrainQueue();
        _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
    }

    [Fact]
    public void SendNotification_DefaultUserName_IsSystem()
    {
        DrainQueue();
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_GeneratesCorrectMessage(EntityOperation op, string expectedVerb)
    {
        DrainQueue();
        _sut.SendNotification("Dept", "5", "Math", op, "User1");

        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains(expectedVerb, notification.Message, StringComparison.OrdinalIgnoreCase);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        DrainQueue();
        var result = _sut.ReceiveNotification();
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_DequeuessInOrder()
    {
        DrainQueue();
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        Assert.Equal("A", first!.EntityType);
        Assert.Equal("B", second!.EntityType);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation but should not throw
        var ex = Record.Exception(() => _sut.MarkAsRead(999));
        Assert.Null(ex);
    }

    [Fact]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        var service = new NotificationService();
        service.Dispose();
        var ex = Record.Exception(() => service.Dispose());
        Assert.Null(ex);
    }
}

