    {
        var student = new Student { LastName = last, FirstMidName = first, EnrollmentDate = DateTime.Today };
        Assert.Equal(expected, student.FullName);
    }

    [Fact]
    public void FullName_WorksForInstructor()
    {
        var instructor = new Instructor { LastName = "Kim", FirstMidName = "Sara", HireDate = DateTime.Today };
        Assert.Equal("Kim, Sara", instructor.FullName);
    }
}

public class ErrorViewModelTests
{
    [Fact]
    public void ShowRequestId_True_WhenRequestIdIsSet()
    {
        var model = new ErrorViewModel { RequestId = "abc123" };
        Assert.True(model.ShowRequestId);
    }

    [Theory]
    [InlineData(null)]
    [InlineData("")]
    public void ShowRequestId_False_WhenRequestIdIsNullOrEmpty(string? requestId)
    {
        var model = new ErrorViewModel { RequestId = requestId! };
        Assert.False(model.ShowRequestId);
    }
}

public class EnrollmentGradeTests
{
    [Fact]
    public void Grade_IsNullable_DefaultsToNull()
    {
        var enrollment = new Enrollment();
        Assert.Null(enrollment.Grade);
    }

    [Theory]
    [InlineData(Grade.A)]
    [InlineData(Grade.F)]
    public void Grade_CanBeSet(Grade grade)
    {
        var enrollment = new Enrollment { Grade = grade };
        Assert.Equal(grade, enrollment.Grade);
    }
}

