using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests
{
    [Fact]
    public void CanCreateContext_WithInMemoryDatabase()
    {
        using var context = TestHelpers.CreateContext();
        Assert.NotNull(context);
        Assert.NotNull(context.Students);
        Assert.NotNull(context.Courses);
        Assert.NotNull(context.Departments);
        Assert.NotNull(context.Instructors);
        Assert.NotNull(context.Enrollments);
        Assert.NotNull(context.CourseAssignments);
        Assert.NotNull(context.OfficeAssignments);
        Assert.NotNull(context.Notifications);
    }

    [Fact]
    public void CourseAssignment_HasCompositeKey()
    {
        using var context = TestHelpers.CreateSeededContext();
        var ca = context.CourseAssignments.First();
        Assert.NotEqual(0, ca.CourseID);
        Assert.NotEqual(0, ca.InstructorID);
    }

    [Fact]
    public void Student_CanAddAndRetrieve()
    {
        using var context = TestHelpers.CreateContext();
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Today
        };
        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.Find(student.ID);
        Assert.NotNull(retrieved);
        Assert.Equal("Test", retrieved!.FirstMidName);
    }

    [Fact]
    public void Course_DepartmentRelationship_Works()
    {
        using var context = TestHelpers.CreateSeededContext();
        var course = context.Courses.Include(c => c.Department).First();
        Assert.NotNull(course.Department);
        Assert.Equal("Engineering", course.Department.Name);
    }

    [Fact]
    public void Instructor_OfficeAssignment_OneToOne()
    {
        using var context = TestHelpers.CreateSeededContext();
        var instructor = context.Instructors
            .Include(i => i.OfficeAssignment)
            .First(i => i.LastName == "Fakhouri");
        Assert.NotNull(instructor.OfficeAssignment);
        Assert.Equal("Smith 17", instructor.OfficeAssignment.Location);
    }

    [Fact]
    public void Enrollment_Relationships_Work()
    {
        using var context = TestHelpers.CreateSeededContext();
        var enrollment = context.Enrollments
            .Include(e => e.Student)
            .Include(e => e.Course)
            .First();
        Assert.NotNull(enrollment.Student);
        Assert.NotNull(enrollment.Course);
        Assert.Equal(Grade.A, enrollment.Grade);
    }
}

