        DbInitializer.Initialize(context);
        Assert.Equal(8, context.CourseAssignments.Count());
    }

    [Fact]
    public void Initialize_WhenAlreadySeeded_DoesNotDuplicate()
    {
        using var context = TestHelpers.CreateContext();
        DbInitializer.Initialize(context);
        var firstCount = context.Students.Count();

        DbInitializer.Initialize(context);
        Assert.Equal(firstCount, context.Students.Count());
    }
}

