        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        // Use the instructor without office assignment to avoid FK issues
        var instructor = _context.Instructors
            .Include(i => i.OfficeAssignment)
            .First(i => i.LastName == "Abercrombie");
        var id = instructor.ID;

        // Clear department administrator reference
        var dept = _context.Departments.FirstOrDefault(d => d.InstructorID == id);
        if (dept != null) dept.InstructorID = null;
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
    }

    [Fact]
    public void DeleteConfirmed_ClearsDepartmentAdministrator()
    {
        // Create a fresh instructor as department admin
        var newInstructor = new Instructor
        {
            FirstMidName = "Temp",
            LastName = "Admin",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(newInstructor);
        _context.SaveChanges();

        var dept = _context.Departments.First();
        dept.InstructorID = newInstructor.ID;
        _context.SaveChanges();

        _controller.DeleteConfirmed(newInstructor.ID);

        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.Null(updatedDept!.InstructorID);
    }
