using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
        // Set up TempData for controller
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_DefaultSort_ReturnsViewWithStudentsOrderedByLastName()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.True(model!.Count > 0);
        // Default sort is by LastName ascending
        var names = model.Select(s => s.LastName).ToList();
        Assert.Equal(names.OrderBy(n => n), names);
    }

    [Fact]
    public void Index_NameDescSort_ReturnsDescendingOrder()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        var names = model!.Select(s => s.LastName).ToList();
        Assert.Equal(names.OrderByDescending(n => n), names);
    }

    [Fact]
    public void Index_DateSort_ReturnsDateAscending()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        var dates = model!.Select(s => s.EnrollmentDate).ToList();
        Assert.Equal(dates.OrderBy(d => d), dates);
    }

    [Fact]
    public void Index_DateDescSort_ReturnsDateDescending()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        var dates = model!.Select(s => s.EnrollmentDate).ToList();
        Assert.Equal(dates.OrderByDescending(d => d), dates);
    }

    [Fact]
    public void Index_SearchString_FiltersResults()
    {
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.Single(model!);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_ResetsPageTo1()
    {
        var result = _controller.Index(null, null, "A", 5) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.Equal(1, model!.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.Single(model!);
    }

    [Fact]
    public void Details_ValidId_ReturnsStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Details(student.ID) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Student;
        Assert.Equal(student.ID, model!.ID);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create() as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Student;
        Assert.NotNull(model);
        Assert.Equal(DateTime.Today, model!.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2024-01-15")
        };

        var result = _controller.Create(student) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
        Assert.Contains(_context.Students, s => s.LastName == "Student");
    }

    [Fact]
    public void Create_Post_InvalidEnrollmentDate_ReturnsViewWithError()
    {
        var student = new Student
        {
            FirstMidName = "Bad",
            LastName = "Date",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_DateOutOfRange_ReturnsViewWithError()
    {
        var student = new Student
        {
            FirstMidName = "Old",
            LastName = "Timer",
            EnrollmentDate = new DateTime(1000, 1, 1)
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "",
            EnrollmentDate = DateTime.Today
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Edit(student.ID) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Student;
        Assert.Equal(student.ID, model!.ID);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(99999) as NotFoundResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        var student = _context.Students.AsNoTracking().First();
        student.FirstMidName = "Updated";

        var result = _controller.Edit(student) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidDate_ReturnsView()
    {
        var student = _context.Students.AsNoTracking().First();
        student.EnrollmentDate = DateTime.MinValue;

        var result = _controller.Edit(student) as ViewResult;
        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Delete(student.ID) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Student;
        Assert.Equal(student.ID, model!.ID);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(99999) as NotFoundResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesStudentAndRedirects()
    {
        var student = _context.Students.First();
        var id = student.ID;

        var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
        Assert.Null(_context.Students.Find(id));
    }
}

