using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsAllCourses()
    {
        var result = _controller.Index() as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as List<Course>;
        Assert.NotNull(model);
        Assert.Equal(2, model!.Count);
    }

    [Fact]
    public void Details_ValidId_ReturnsCourse()
    {
        var course = _context.Courses.First();
        var result = _controller.Details(course.CourseID) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Course;
        Assert.Equal(course.CourseID, model!.CourseID);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithDepartmentList()
    {
        var result = _controller.Create() as ViewResult;
        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var result = _controller.Create(course, null!) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
        Assert.NotNull(_context.Courses.Find(9999));
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 8888 };

        var result = _controller.Create(course, null!) as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Post_InvalidImageExtension_ReturnsViewWithError()
    {
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 7777,
            Title = "Bad Image",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.exe");
        fileMock.Setup(f => f.Length).Returns(100);

        var result = _controller.Create(course, fileMock.Object) as ViewResult;
        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_OversizedImage_ReturnsViewWithError()
    {
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 6666,
            Title = "Big Image",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("big.jpg");
        fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

        var result = _controller.Create(course, fileMock.Object) as ViewResult;
        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_ValidImage_UploadsAndRedirects()
    {
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 5555,
            Title = "With Image",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.jpg");
        fileMock.Setup(f => f.Length).Returns(1024);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
        var saved = _context.Courses.Find(5555);
        Assert.NotNull(saved);
        Assert.StartsWith("/Uploads/TeachingMaterials/", saved!.TeachingMaterialImagePath);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsCourse()
    {
        var course = _context.Courses.First();
        var result = _controller.Edit(course.CourseID) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Course;
        Assert.Equal(course.CourseID, model!.CourseID);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(99999) as NotFoundResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = _context.Courses.AsNoTracking().First();
        course.Title = "Updated Title";

        var result = _controller.Edit(course, null!) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidImageExtension_ReturnsViewWithError()
    {
        var course = _context.Courses.AsNoTracking().First();
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("hack.txt");
        fileMock.Setup(f => f.Length).Returns(100);

        var result = _controller.Edit(course, fileMock.Object) as ViewResult;
        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsCourse()
    {
        var course = _context.Courses.First();
        var result = _controller.Delete(course.CourseID) as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        var course = _context.Courses.First();
        var id = course.CourseID;

        var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
        Assert.Null(_context.Courses.Find(id));
    }
}

