    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsAllDepartments()
    {
        var result = _controller.Index() as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as List<Department>;
        Assert.NotNull(model);
        Assert.Single(model!);
    }

    [Fact]
    public void Details_ValidId_ReturnsDepartment()
    {
        var dept = _context.Departments.First();
        var result = _controller.Details(dept.DepartmentID) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Department;
        Assert.Equal(dept.DepartmentID, model!.DepartmentID);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(99999) as NotFoundResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Get_SetsInstructorSelectList()
    {
        var result = _controller.Create() as ViewResult;
        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var instructor = _context.Instructors.First();
        var dept = new Department
        {
            Name = "Mathematics",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor.ID
        };

        var result = _controller.Create(dept) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
        Assert.Equal(2, _context.Departments.Count());
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department();

        var result = _controller.Create(dept) as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsDepartment()
    {
        var dept = _context.Departments.First();
        var result = _controller.Edit(dept.DepartmentID) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Department;
        Assert.Equal(dept.DepartmentID, model!.DepartmentID);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(99999) as NotFoundResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = _context.Departments.AsNoTracking().First();
        dept.Name = "Updated";

        var result = _controller.Edit(dept) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = _context.Departments.AsNoTracking().First();

        var result = _controller.Edit(dept) as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsDepartment()
    {
        var dept = _context.Departments.First();
        var result = _controller.Delete(dept.DepartmentID) as ViewResult;
        Assert.NotNull(result);
        var model = result!.Model as Department;
        Assert.Equal(dept.DepartmentID, model!.DepartmentID);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;
        Assert.Equal((int)HttpStatusCode.BadRequest, result!.StatusCode);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(99999) as NotFoundResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        var dept = _context.Departments.First();
        var id = dept.DepartmentID;

        var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result!.ActionName);
        Assert.Null(_context.Departments.Find(id));
    }
}

